    code: `#!/bin/bash

# Check if network prefix is provided
if [ $# -ne 1 ]; then
    echo "Usage: $0 <network-prefix>"
    echo "Example: $0 192.168.1"
    exit 1
fi

network=$1
echo "Scanning network: $network.0/24"
echo "Live hosts:"

# Loop through all possible hosts in a /24 subnet
for host in {1..254}; do
    # Ping each host once with a timeout of 1 second
    ping -c 1 -W 1 "$network.$host" > /dev/null 2>&1
    
    # If ping was successful, print the IP address
    if [ $? -eq 0 ]; then
        echo "$network.$host is up"
    fi
done

echo "Scan complete."`,
    usage: "./subnet_scanner.sh 192.168.1",
    requirements: ["Bash shell", "ping utility"]
